var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"본부, 관측소에 도착했다! 현 시간부로 작전을 개시한다!","JPN":"本部、観測所に到着した！　現時刻をもって作戦を開始する！","ENG":"HQ, we've arrived at the observation post. Commencing operation now.","TWN":"總部，到達觀測站！現在開始作戰！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"3소대는 관측소 밖에서 경계 태세로, 1소대와 2소대는 각각 지상과 지하시설을 수색한다!","JPN":"第3小隊は観測所の外で警戒態勢を、第1小隊と第2小隊はそれぞれ地上と地下施設を捜索せよ！","ENG":"Squad 3, be on guard outside the post. Squad 1 and 2, search the ground and underground facilities respectively.","TWN":"3小隊在觀測站外保持警戒，1小隊和2小隊分別搜索地上和地下設施。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"관측소 대원들의 신변 확보가 최우선이다! 어서 움직여!","JPN":"観測所の隊員たちの身柄確保が最優先だ！　早く行け！","ENG":"Securing the safety of Observation Post personnel is your top priority. Move, move!","TWN":"最優先確保觀測站隊員的人身安全！快行動！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정말이군...... 미량이긴 해도 허수 에너지가 남아 있어.","JPN":"本当だ……微量ではあるが、ノイズエネルギーが残っているな。","ENG":"It's true. The Imaginary Energy still remains, although at a very low level.","TWN":"真的啊……雖說只有微量，但殘留著虛數能量。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정말로 학회장이 바뀌기라도 한 건가? 아니면......","JPN":"本当に学会長が替わったのか？　それとも……","ENG":"Has the President of the Society really changed? Or...","TWN":"學會長真的換人了？還是說……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님, 관측소 직원들은 대부분 사망한 것 같습니다.","JPN":"観測所の職員はほとんど死亡したようです。","ENG":"Sir, I'm afraid there's no survivors among the personnel.","TWN":"要員，我想大部分的觀測站隊員都死亡了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"시신들의 상태는 어떤가?","JPN":"死体の状態は？","ENG":"What were the deceased like?","TWN":"遺體的狀況如何？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"외상은 없는데 다들 잔뜩 겁에 질린 표정이더군요.","JPN":"外傷はありませんが、皆かなり怯えた表情をしていますね。","ENG":"There were no external injuries, but they all looked frightened.","TWN":"沒有外傷，但是他們都露出了極度驚恐的表情。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"꼭...... 공포 영화에나 나올 법한 상황 같습니다.","JPN":"まるで……ホラー映画にでも出てきそうな状況です。","ENG":"It was like... a scene in a horror movie.","TWN":"就像……恐怖電影裡的場景一樣。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"요원님? 괜찮으십니까?","JPN":"大丈夫ですか？","ENG":"Sir, are you all right?","TWN":"要員？您沒事吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아, 미안하네. 생각할 게 좀 있어서 말일세.","JPN":"ああ、すまない。ちょっと考え事をしていたんだ。","ENG":"Ah, I'm sorry. I was lost in thought.","TWN":"啊，抱歉。我想了些事情。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"여기 오신 뒤로 그 낡은 계산기만 들여다보시는군요. 어디에 쓰는 물건입니까?","JPN":"ここに来てから、その古い計算機ばかり見ていますね。何に使う物なんですか？","ENG":"You've been looking at that old calculator the whole time. May I ask what it is for?","TWN":"來到這裡之後，您就一直在看那個破舊的計算機，這是用在什麼地方的東西啊？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"자네가 몰라도 되는 특수한 에너지를 포착하는 아티팩트지.","JPN":"君は知る必要のない、特殊なエネルギーを捉えるためのアーティファクトだ。","ENG":"It's an artifact that detects special energy, which you don't need to know about.","TWN":"你不知道也無所謂，這是種捕捉特殊能量的人造神器。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고 작전은 중단일세. 당장 철수 준비하게.","JPN":"それから、作戦は中断しろ。すぐに撤収の準備を始めるんだ。","ENG":"And this operation is over. Prepare to evacuate immediately.","TWN":"另外，作戰終止。立刻準備撤退。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"네? 갑자기 무슨 말씀이십니까?","JPN":"え？　突然どういうことですか？","ENG":"Say that again, sir?","TWN":"咦？您突然說些什麼呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"아직 모든 직원들의 생사를 확인한 건 아닙니다. 이대로는......","JPN":"まだ全ての職員の生死を確認したわけではありません。このままでは……","ENG":"We haven't checked all the areas. We can't leave like—huh?","TWN":"我們還沒有確認所有作業員的生死，這樣下去……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};